#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void extract_kernel(const long d_Ne,
                             __global float *d_I) {
    const long ei = (long)get_group_id(0) * (long)get_local_size(0) + (long)get_local_id(0);
    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

__kernel void prepare_kernel(const long d_Ne,
                             __global float *d_I,
                             __global float *d_sums,
                             __global float *d_sums2) {
    const long ei = (long)get_group_id(0) * (long)get_local_size(0) + (long)get_local_id(0);
    if (ei < d_Ne) {
        float v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(const long d_Ne,
                            const long d_no,
                            const int d_mul,
                            __global float *d_sums,
                            __global float *d_sums2,
                            const int d_blocks) {
    (void)d_Ne;

    const int bx = (int)get_group_id(0);
    const int tx = (int)get_local_id(0);
    const int ls = (int)get_local_size(0);
    const int ei = bx * ls + tx;
    const int nf = ls - (d_blocks * ls - (int)d_no);

    __local float lsum[1024];
    __local float lsum2[1024];

    float v1 = 0.0f;
    float v2 = 0.0f;
    if (ei < (int)d_no) {
        const int idx = ei * d_mul;
        v1 = d_sums[idx];
        v2 = d_sums2[idx];
    }
    lsum[tx] = v1;
    lsum2[tx] = v2;
    barrier(CLK_LOCAL_MEM_FENCE);

    if (nf == ls || bx != (d_blocks - 1)) {
        for (int i = 2; i <= ls; i <<= 1) {
            if (((tx + 1) % i) == 0) {
                lsum[tx] += lsum[tx - (i >> 1)];
                lsum2[tx] += lsum2[tx - (i >> 1)];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (ls - 1)) {
            const int out_idx = bx * d_mul * ls;
            d_sums[out_idx] = lsum[tx];
            d_sums2[out_idx] = lsum2[tx];
        }
    } else {
        int df = 0;
        for (int i = 2; i <= ls; i <<= 1) {
            if (nf >= i) df = i;
        }

        for (int i = 2; i <= df; i <<= 1) {
            if (((tx + 1) % i) == 0 && tx < df) {
                lsum[tx] += lsum[tx - (i >> 1)];
                lsum2[tx] += lsum2[tx - (i >> 1)];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (df - 1)) {
            for (int i = bx * ls + df; i < bx * ls + nf; i++) {
                lsum[tx] += d_sums[i];
                lsum2[tx] += d_sums2[i];
            }
            const int out_idx = bx * d_mul * ls;
            d_sums[out_idx] = lsum[tx];
            d_sums2[out_idx] = lsum2[tx];
        }
    }
}

__kernel void srad_kernel(const float lambda,
                          const int Nr,
                          const int Nc,
                          const long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global float *d_dN,
                          __global float *d_dS,
                          __global float *d_dW,
                          __global float *d_dE,
                          const float q0sqr,
                          __global float *d_c,
                          __global float *d_I) {
    (void)lambda;
    const long ei = (long)get_group_id(0) * (long)get_local_size(0) + (long)get_local_id(0);
    if (ei >= Ne) return;

    const int row = (int)(ei / (long)Nc);
    const int col = (int)(ei - (long)row * (long)Nc);

    if (row < Nr && col < Nc) {
        const int k = row * Nc + col;
        const float Jc = d_I[k];

        const float dN = d_I[iN[row] * Nc + col] - Jc;
        const float dS = d_I[iS[row] * Nc + col] - Jc;
        const float dW = d_I[row * Nc + jW[col]] - Jc;
        const float dE = d_I[row * Nc + jE[col]] - Jc;

        d_dN[k] = dN;
        d_dS[k] = dS;
        d_dW[k] = dW;
        d_dE[k] = dE;

        const float G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        const float L = (dN + dS + dW + dE) / Jc;
        const float num = 0.5f * G2 - 0.0625f * (L * L);
        float den = 1.0f + 0.25f * L;
        const float qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        float c = 1.0f / (1.0f + den);

        if (c < 0.0f) c = 0.0f;
        else if (c > 1.0f) c = 1.0f;

        d_c[k] = c;
    }
}

__kernel void srad2_kernel(const float lambda,
                           const int Nr,
                           const int Nc,
                           const long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global float *d_dN,
                           __global float *d_dS,
                           __global float *d_dW,
                           __global float *d_dE,
                           __global float *d_c,
                           __global float *d_I) {
    (void)iN;
    (void)jW;

    const long ei = (long)get_group_id(0) * (long)get_local_size(0) + (long)get_local_id(0);
    if (ei >= Ne) return;

    const int row = (int)(ei / (long)Nc);
    const int col = (int)(ei - (long)row * (long)Nc);

    if (row < Nr && col < Nc) {
        const int k = row * Nc + col;

        const float cN = d_c[k];
        const float cS = d_c[iS[row] * Nc + col];
        const float cW = d_c[k];
        const float cE = d_c[row * Nc + jE[col]];

        const float D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];
        d_I[k] = d_I[k] + 0.25f * lambda * D;
    }
}

__kernel void compress_kernel(const long d_Ne,
                              __global float *d_I) {
    const long ei = (long)get_group_id(0) * (long)get_local_size(0) + (long)get_local_id(0);
    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}
